import{_ as a,o as i,c as t,a0 as l}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Alliance Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/alliance.md","filePath":"analytics/alliance.md"}'),s={name:"analytics/alliance.md"};function n(o,e,r,c,h,d){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="alliance-analytics" tabindex="-1">Alliance Analytics <a class="header-anchor" href="#alliance-analytics" aria-label="Permalink to &quot;Alliance Analytics&quot;">​</a></h1><p>The <strong>Alliance</strong> tab is the main analytics view for day-to-day leadership work. It shows how one alliance is performing across tracked events and which players may need attention.</p><p>If this is your first premium analytics page, see <a href="./../subscriptions/premium-features.html">Premium Features</a> for the locked/active pattern used by premium-only parts of analytics.</p><blockquote><p>Screenshot placeholder: <code>analytics-alliance.png</code> (S50)</p></blockquote><h2 id="who-this-is-for" tabindex="-1">Who this is for <a class="header-anchor" href="#who-this-is-for" aria-label="Permalink to &quot;Who this is for&quot;">​</a></h2><p>This page is useful for:</p><ul><li><code>King</code> users reviewing one alliance inside their kingdom</li><li><code>Alliance Leader</code> and <code>Co-Leader</code> users managing their own alliance</li><li>alliance-scoped readers who are allowed to view analytics</li></ul><h2 id="what-you-will-see" tabindex="-1">What you will see <a class="header-anchor" href="#what-you-will-see" aria-label="Permalink to &quot;What you will see&quot;">​</a></h2><p>The Alliance tab usually includes:</p><ul><li>summary cards for members, alliance power, event score, participation, internal points, and watchlist size</li><li>trend charts for alliance tempo and event discipline</li><li>a damage leaderboard</li><li>momentum panels showing who is rising and who is slipping compared with their own recent pattern</li><li>a member table with score, average, participation, missed events, and status</li></ul><p>Selecting a player opens that player&#39;s deeper analytics view when your premium player feature is active.</p><h2 id="alliance-recommendations-slot" tabindex="-1">Alliance recommendations slot <a class="header-anchor" href="#alliance-recommendations-slot" aria-label="Permalink to &quot;Alliance recommendations slot&quot;">​</a></h2><p>This tab also contains the place where alliance follow-up recommendations appear.</p><p>When the relevant premium recommendation feature is active, the page can show:</p><ul><li>an inactivity watchlist</li><li>follow-up suggestions for players with low participation or inactive patterns</li></ul><p>When that feature is not active, the page shows a notice instead of those recommendation details. For the full recommendation picture, including cleanup suggestions outside analytics, see <a href="./recommendations.html">Smart Recommendations</a>.</p><h2 id="what-this-tab-is-best-for" tabindex="-1">What this tab is best for <a class="header-anchor" href="#what-this-tab-is-best-for" aria-label="Permalink to &quot;What this tab is best for&quot;">​</a></h2><p>Use Alliance analytics when you want to:</p><ul><li>review your strongest and weakest performers</li><li>check if participation is slipping</li><li>compare event categories</li><li>decide which players need follow-up before rewards or reminders</li></ul><h2 id="related-guides" tabindex="-1">Related guides <a class="header-anchor" href="#related-guides" aria-label="Permalink to &quot;Related guides&quot;">​</a></h2><ul><li><a href="./overview.html">Analytics Overview</a></li><li><a href="./player-cross-event.html">Player Cross-Event Analytics</a></li><li><a href="./recommendations.html">Smart Recommendations</a></li><li><a href="./../how-to/rewards.html">Review Reward Eligibility</a></li></ul>',21)])])}const u=a(s,[["render",n]]);export{m as __pageData,u as default};
